import React, { useState, useEffect } from 'react';
import api from '../api';

const AnalyticsDashboard = () => {
  const [analytics, setAnalytics] = useState(null);
  const [year, setYear] = useState(2024);
  const [month, setMonth] = useState(1);

  useEffect(() => {
    fetchAnalytics();
  }, [year, month]);

  const fetchAnalytics = async () => {
    try {
      const res = await api.get(`/analytics/monthly?year=${year}&month=${month}`);
      setAnalytics(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  if (!analytics) return <div className="flex items-center justify-center p-12 text-indigo-500 font-bold animate-pulse text-xl">Loading metrics...</div>;

  return (
    <div className="glass-card rounded-[2.5rem] p-10 h-full border border-white/5">
      <div className="flex justify-between items-center mb-10">
        <div>
          <h3 className="text-2xl font-black text-white tracking-tight">Financial Health</h3>
          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-1">Intelligence engine</p>
        </div>
        <div className="flex items-center space-x-2 bg-white/5 p-2 rounded-[1.5rem] border border-white/5">
          <input type="number" value={year} onChange={(e) => setYear(e.target.value)} className="w-20 p-2.5 bg-transparent text-white font-bold outline-none text-center" />
          <div className="w-px h-6 bg-white/10"></div>
          <input type="number" min="1" max="12" value={month} onChange={(e) => setMonth(e.target.value)} className="w-12 p-2.5 bg-transparent text-white font-bold outline-none text-center" />
          <button onClick={fetchAnalytics} className="bg-white/10 hover:bg-white/20 text-white px-5 py-2.5 rounded-xl font-bold text-xs uppercase tracking-widest transition-all">Update</button>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="p-8 bg-emerald-500/5 rounded-3xl border border-emerald-500/10 hover:bg-emerald-500/10 transition-all group">
          <h3 className="text-[10px] font-black text-emerald-500/60 mb-2 tracking-[0.2em] uppercase">Savings Rate</h3>
          <p className="text-5xl font-black text-white group-hover:scale-105 transition-transform">{parseFloat(analytics.savingsRate || 0).toFixed(1)}<span className="text-xl opacity-30 ml-1">%</span></p>
        </div>
        <div className="p-8 bg-indigo-500/5 rounded-3xl border border-indigo-500/10 hover:bg-indigo-500/10 transition-all group">
          <h3 className="text-[10px] font-black text-indigo-500/60 mb-2 tracking-[0.2em] uppercase">Volatility</h3>
          <p className="text-5xl font-black text-white group-hover:scale-105 transition-transform"><span className="text-xl opacity-30 mr-1 text-indigo-400">$</span>{parseFloat(analytics.expenseStd || 0).toFixed(0)}</p>
        </div>
        <div className="p-8 bg-rose-500/5 rounded-3xl border border-rose-500/10 hover:bg-rose-500/10 transition-all group">
          <h3 className="text-[10px] font-black text-rose-500/60 mb-2 tracking-[0.2em] uppercase">Efficiency</h3>
          <p className="text-5xl font-black text-white group-hover:scale-105 transition-transform">{(parseFloat(analytics.budgetUsage || 0) * 100).toFixed(1)}<span className="text-xl opacity-30 ml-1">%</span></p>
        </div>
      </div>
    </div>
  );
};

export default AnalyticsDashboard;
